SAFE_CONSTS = {True, False, None}

def _validate_ast(node):
    """Recursively validate AST nodes are safe."""
    node_type = node.__class__.__name__
    if node_type not in SAFE_NODES:
        raise ValueError(f"Unsafe node: {node_type}")

    # Check operators and constants
    if isinstance(node, ast.Constant):
        if node.value is not None and not isinstance(node.value, (int, float, str, bool)):
            raise ValueError("Unsafe constant type")
    elif isinstance(node, (ast.Num, ast.Str, ast.NameConstant)):
        # For older Python versions compatibility
        pass
    elif isinstance(node, ast.BinOp):
        if type(node.op) not in SAFE_OPS:
            raise ValueError("Unsafe binary operator")
        _validate_ast(node.left)
        _validate_ast(node.right)
    elif isinstance(node, ast.UnaryOp):
        if type(node.op) not in SAFE_OPS:
            raise ValueError("Unsafe unary operator")
        _validate_ast(node.operand)
    elif isinstance(node, ast.BoolOp):
        if type(node.op) not in SAFE_OPS:
            raise ValueError("Unsafe boolean operator")
        for value in node.values:
            _validate_ast(value)
    elif isinstance(node, ast.Compare):
        for op in node.ops:
            if type(op) not in SAFE_OPS:
                raise ValueError("Unsafe comparison operator")
        _validate_ast(node.left)
        for comparator in node.comparators:
            _validate_ast(comparator)
    elif isinstance(node, ast.Name):
        # Allow only specific names (e.g., 'True', 'False', 'None')
        if node.id not in {'True', 'False', 'None'}:
            raise ValueError("Unsafe name reference")
