def safe_eval(expr):
    """Safely evaluate a limited expression."""
    try:
        tree = ast.parse(expr, mode='eval')
    except SyntaxError:
        raise ValueError("Invalid syntax")

    _validate_ast(tree.body)

    # Evaluate with no builtins and restricted globals
    return eval(compile(tree, '<string>', 'eval'), {"__builtins__": {}}, {})

